/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // Initialize the grid with 0 (uncolored)
    const grid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Distance and color tracking for each cell: [distance, color]
    // Initialize with infinity distance and color 0
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));
    const colorGrid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Priority Queue for Dijkstra-like approach: [time, color, r, c]
    // We prioritize smaller time, and for ties in time, larger color.
    // Since we are simulating BFS/Dijkstra on time/distance, a standard min-heap on distance works.
    // To handle the color tie-breaking rule (max color wins), we need a slightly modified approach
    // or process events carefully.

    // A standard BFS structure tracking time works well for distance.
    // We use a deque/queue structure suitable for 0-1 BFS, but here all weights are 1 (one time step).
    // However, the color update rule complicates a simple BFS.

    // Let's use a Min-Heap (Priority Queue) storing: [distance, -color, r, c]
    // We use -color because a Min-Heap prioritizes smaller values. If distances are equal,
    // a smaller -color means a larger color (since color > 0).
    const pq = new MinPriorityQueue({ priority: x => [x[0], x[1]] });

    // Initialize the priority queue with source nodes
    for (const [r, c, color] of sources) {
        dist[r][c] = 0;
        colorGrid[r][c] = color;
        // Priority: [distance, negative_color, r, c]
        pq.enqueue([0, -color, r, c]);
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    while (!pq.isEmpty()) {
        const { element: [d, negC, r, c] } = pq.dequeue();
        const current_color = -negC;

        // If we found a path to (r, c) that is strictly worse than what's already recorded, skip it.
        // Note: If d > dist[r][c], it means we found a longer path previously, skip.
        // If d == dist[r][c], we only process if the color is better (higher),
        // but Dijkstra guarantees the first time we extract a node, it's the best path *so far*.
        // Since the color is part of the "value" we care about, we must check consistency.
        if (d > dist[r][c] || (d === dist[r][c] && current_color < colorGrid[r][c])) {
            continue;
        }

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const new_dist = d + 1;
                const neighbor_current_color = colorGrid[nr][nc];

                let shouldUpdate = false;

                if (new_dist < dist[nr][nc]) {
                    // Case 1: Shorter path found. Always update.
                    shouldUpdate = true;
                } else if (new_dist === dist[nr][nc]) {
                    // Case 2: Same distance. Update only if the incoming color is strictly larger.
                    if (current_color > neighbor_current_color) {
                        shouldUpdate = true;
                    }
                }

                if (shouldUpdate) {
                    dist[nr][nc] = new_dist;
                    colorGrid[nr][nc] = current_color;
                    pq.enqueue([new_dist, -current_color, nr, nc]);
                }
            }
        }
    }

    return colorGrid;
}

