        this._heap = [];
        this._priority = priority;
    }

    _getParentIndex(i) { return Math.floor((i - 1) / 2); }
    _getLeftChildIndex(i) { return 2 * i + 1; }
    _getRightChildIndex(i) { return 2 * i + 2; }

    _swap(i, j) {
        [this._heap[i], this._heap[j]] = [this._heap[j], this._heap[i]];
    }

    _compare(i, j) {
        // Returns true if element at i has higher priority (smaller value) than element at j
        return this._priority(this._heap[i]) < this._priority(this._heap[j]);
    }

    enqueue(element) {
        this._heap.push(element);
        this._bubbleUp(this._heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this._heap.length === 1) return { element: this._heap.pop() };

        const min = this._heap[0];
        this._heap[0] = this._heap.pop();
        this._bubbleDown(0);
        return { element: min };
    }

    isEmpty() {
        return this._heap.length === 0;
    }

    _bubbleUp(index) {
        let currentIndex = index;
        let parentIndex = this._getParentIndex(currentIndex);

        while (currentIndex > 0 && this._compare(currentIndex, parentIndex)) {
            this._swap(currentIndex, parentIndex);
            currentIndex = parentIndex;
            parentIndex = this._getParentIndex(currentIndex);
        }
    }

    _bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this._heap.length - 1;

        while (true) {
            let leftChildIndex = this._getLeftChildIndex(currentIndex);
            let rightChildIndex = this._getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (leftChildIndex <= lastIndex && this._compare(leftChildIndex, smallest)) {
                smallest = leftChildIndex;
            }

            // Check right child
            if (rightChildIndex <= lastIndex && this._compare(rightChildIndex, smallest)) {
                smallest = rightChildIndex;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}

